package com.recettealarm.app;
import android.content.*;import android.database.*;import android.database.sqlite.*;import org.json.*;import java.util.*;
public class DB extends SQLiteOpenHelper{ public DB(Context c){super(c,"recette_alarm.db",null,1);} public void onCreate(SQLiteDatabase d){d.execSQL("CREATE TABLE recipes(id INTEGER PRIMARY KEY,title TEXT,category TEXT,servings INT,time INT,video TEXT,fav INT,created TEXT)");d.execSQL("CREATE TABLE ingredients(id INTEGER PRIMARY KEY,recipe_id INT,name TEXT,qty TEXT,unit TEXT,ord INT)");d.execSQL("CREATE TABLE steps(id INTEGER PRIMARY KEY,recipe_id INT,ord INT,description TEXT,duration INT,alarm INT,note TEXT)");seed(d);} public void onUpgrade(SQLiteDatabase d,int o,int n){}
 void seed(SQLiteDatabase d){ContentValues r=new ContentValues();r.put("title","Tajine Poulet aux Olives");r.put("category","Tajines");r.put("servings",4);r.put("time",45);r.put("fav",1);r.put("created","now");long id=d.insert("recipes",null,r);String[][] ing={{"Poulet fermier","1.5","kg"},{"Olives vertes","1","verre"},{"Oignons","2","pièce"},{"Safran","1","pincée"}};for(int i=0;i<ing.length;i++){ContentValues v=new ContentValues();v.put("recipe_id",id);v.put("name",ing[i][0]);v.put("qty",ing[i][1]);v.put("unit",ing[i][2]);v.put("ord",i);d.insert("ingredients",null,v);}String[][] st={{"Faire revenir le poulet dans l'huile d'olive.","10","Remuer et vérifier le feu"},{"Ajouter oignons, épices et eau.","20","Vérifier l'eau"},{"Ajouter les olives et réduire le feu.","15","Baisser le feu au minimum"}};for(int i=0;i<st.length;i++){ContentValues v=new ContentValues();v.put("recipe_id",id);v.put("ord",i+1);v.put("description",st[i][0]);v.put("duration",Integer.parseInt(st[i][1]));v.put("alarm",1);v.put("note",st[i][2]);d.insert("steps",null,v);}}
 Cursor recipes(){return getReadableDatabase().rawQuery("SELECT * FROM recipes ORDER BY id DESC",null);} Cursor one(long id){return getReadableDatabase().rawQuery("SELECT * FROM recipes WHERE id=?",new String[]{id+""});} Cursor ingredients(long id){return getReadableDatabase().rawQuery("SELECT * FROM ingredients WHERE recipe_id=? ORDER BY ord,id",new String[]{id+""});} Cursor steps(long id){return getReadableDatabase().rawQuery("SELECT * FROM steps WHERE recipe_id=? ORDER BY ord,id",new String[]{id+""});}
 long saveRecipe(long id,String title,String cat,int servings,int time,String video){ContentValues v=new ContentValues();v.put("title",title);v.put("category",cat);v.put("servings",servings);v.put("time",time);v.put("video",video);v.put("created",new Date().toString());if(id>0){getWritableDatabase().update("recipes",v,"id=?",new String[]{id+""});return id;}return getWritableDatabase().insert("recipes",null,v);} void addIng(long rid,String n,String q,String u){ContentValues v=new ContentValues();v.put("recipe_id",rid);v.put("name",n);v.put("qty",q);v.put("unit",u);getWritableDatabase().insert("ingredients",null,v);} void addStep(long rid,String d,int min,String note){ContentValues v=new ContentValues();v.put("recipe_id",rid);v.put("description",d);v.put("duration",min);v.put("alarm",1);v.put("note",note);v.put("ord",99);getWritableDatabase().insert("steps",null,v);} void del(String table,long id){getWritableDatabase().delete(table,"id=?",new String[]{id+""});}
 String shoppingList(){Cursor c=getReadableDatabase().rawQuery("SELECT name,qty,unit FROM ingredients",null);StringBuilder s=new StringBuilder("Liste de courses:\n");while(c.moveToNext())s.append("• ").append(c.getString(0)).append(" - ").append(c.getString(1)).append(" ").append(c.getString(2)).append('\n');c.close();return s.toString();}
}
